// Prefer high-level Solidity: the compiler is usually efficient enough.
// Bad:
// assembly { result := add(a, b) } // no overflow check
// Good:
uint256 result = a + b; // reverts on overflow in 0.8+

// If assembly is genuinely required (e.g. low-level calls, gas-critical hot paths):
function extractSelector(bytes memory data) internal pure returns (bytes4 sel) {
    // 1. Keep the block as small as possible and mark it memory-safe.
    // 2. Document every invariant the surrounding Solidity code must uphold.
    // Invariant: data.length >= 4, checked by the caller.
    assembly ("memory-safe") {
        sel := mload(add(data, 32))
    }
}
